    private fun starter(
        id: String,
        label: String,
        speech: String,
        meaningId: String,
        meaningType: String,
        meaningGroup: String,
        semanticTags: List<String>,
        visibleUnderIds: List<String> = emptyList(),
        addsToSentence: Boolean = false,
        fixedTopRowPosition: Int? = null,
        placements: List<AacPlacement> = emptyList(),
        opensSubicons: Boolean = false,
        children: List<String> = emptyList(),
        questionByLanguage: Map<String, String> = emptyMap(),
        labelByLanguage: Map<String, String> = emptyMap(),
        speechTextByLanguage: Map<String, String> = emptyMap(),
        targetPageId: String = "",
        imagePath: String = "",
        iconSource: IconSource = IconSource.SYSTEM
    ): AacItem {
        val effectiveQuestionByLanguage = questionByLanguage.withDefaultUk(
            UK_QUESTION_BY_SL[questionByLanguage["sl"]?.trim().orEmpty()]
        )
        val effectiveLabelByLanguage = labelByLanguage.withDefaultUk(
            UK_LABEL_BY_ID[id] ?: UK_LABEL_BY_SL[label.trim()]
        )
        val effectiveSpeechTextByLanguage = speechTextByLanguage.withDefaultUk(
            UK_SPEECH_BY_ID[id] ?: defaultUkSpeechText(
                labelUk = effectiveLabelByLanguage["uk"].orEmpty(),
                meaningType = meaningType,
                meaningGroup = meaningGroup
            )
        )
        val effectiveImagePath = safeStarterSystemIconPath(
            id = id,
            meaningType = meaningType,
            meaningGroup = meaningGroup,
            imagePath = imagePath,
            iconSource = iconSource
        )
        return AacItem(
            id = id,
            labelSl = label,
            imagePath = effectiveImagePath,
            actionType = when {
                targetPageId.isNotBlank() -> "open_page"
                opensSubicons -> "open_subicons"
                else -> "speak"
            },
            targetPageId = targetPageId,
            speakTextSl = speech,
            speechText = speech,
            iconSource = IconSource.SYSTEM,
            suggestedIconPath = suggestedIconPath(IconSource.SYSTEM, effectiveImagePath),
            isRootItem = visibleUnderIds.isEmpty(),
            isHiddenUntilParent = false,
            visibleUnderIds = visibleUnderIds,
            canAppearInMultipleParents = true,
            children = children,
            placements = placements,
            protectedPlacement = fixedTopRowPosition != null || id in CORE_V2_PROTECTED_MAIN_IDS,
            questionByLanguage = effectiveQuestionByLanguage,
            labelByLanguage = effectiveLabelByLanguage,
            speechTextByLanguage = effectiveSpeechTextByLanguage,
            addsToSentence = addsToSentence,
            speaksImmediately = !opensSubicons,
            opensSubicons = opensSubicons,
            semanticType = semanticTypeFor(meaningType),
            meaningId = meaningId,
            meaningType = meaningType,
            meaningGroup = meaningGroup,
            fixedTopRowPosition = fixedTopRowPosition,
            semanticTags = semanticTags,
            searchKeywordsByLanguage = mapOf("sl" to semanticTags),
            priority = START_PRIORITY + STARTER_IDS.indexOf(id).takeIf { it >= 0 }.orZero()
        )
    }

    private fun Map<String, String>.withDefaultUk(defaultUk: String?): Map<String, String> {
        val cleaned = defaultUk?.trim().orEmpty()
        if (cleaned.isBlank() || containsKey("uk")) return this
        return this + ("uk" to cleaned)
    }

    private fun defaultUkSpeechText(
        labelUk: String,
        meaningType: String,
        meaningGroup: String
    ): String {
        val spokenLabel = labelUk.lowercase()
        return when (meaningType.trim().uppercase()) {
            "DRINK" -> "Будь ласка, я хочу $spokenLabel."
            "FOOD" -> "Будь ласка, я хочу $spokenLabel."
            "PAIN", "BODY_PART" -> "У мене болить $spokenLabel."
            "NEED", "HELPER" -> "Мені потрібно: $spokenLabel."
            "PEOPLE" -> "Я хочу поговорити про: $spokenLabel."
            "PLACE" -> "Я хочу туди: $spokenLabel."
            "TIME" -> "$labelUk."
            "QUESTION" -> "$labelUk?"
            "FEELING", "STATE", "CONFIRMATION", "CORE_ACTION", "ACTION", "MODIFIER", "SCENARIO" -> "$labelUk."
            else -> if (meaningGroup == "pain") "У мене болить $spokenLabel." else "$labelUk."
        }
    }

    private fun safeStarterSystemIconPath(
        id: String,
        meaningType: String,
        meaningGroup: String,
        imagePath: String,
        iconSource: IconSource
    ): String {
        val normalizedPath = imagePath.trim().replace('\\', '/').removePrefix("/")
        if (iconSource == IconSource.SYSTEM && normalizedPath in SAFE_SYSTEM_ICON_PATHS) {
            return normalizedPath
        }
        return SYSTEM_ICON_BY_STARTER_ID[id]
            ?: SYSTEM_ICON_BY_MEANING_GROUP[meaningGroup.trim().lowercase()]
            ?: SYSTEM_ICON_BY_MEANING_TYPE[meaningType.trim().uppercase()]
            ?: "system/other.png"
    }

